#include <stdio.h>
#include <stdlib.h>

struct Node {int v; struct Node *next;};

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n,m; scanf("%d %d", &n, &m);
        struct Node **adj = (struct Node**)calloc(n+1, sizeof(struct Node*));
        int *vis = (int*)calloc(n+1, sizeof(int));
        for(int i=0;i<m;++i){
            int a,b; scanf("%d %d", &a, &b);
            struct Node *p = (struct Node*)malloc(sizeof(struct Node));
            p->v = b; p->next = adj[a]; adj[a] = p;
        }
        int *stack = (int*)malloc((n+5)*sizeof(int));
        int top=0; stack[top++] = 1; vis[1]=1;
        while(top){
            int v = stack[--top];
            for(struct Node *cur = adj[v]; cur; cur = cur->next){
                int u = cur->v;
                if(!vis[u]){vis[u]=1; stack[top++] = u;}
            }
        }
        for(int i=1;i<=n;++i) if(vis[i]) printf("%d ", i);
        printf("\n");
        // free memory
        for(int i=1;i<=n;++i){
            struct Node *cur = adj[i];
            while(cur){ struct Node *tmp = cur; cur = cur->next; free(tmp); }
        }
        free(adj); free(vis); free(stack);
    }
    return 0;
}

