import sys

def solve_one(it):
    n = int(next(it))
    m = int(next(it))
    adj = [[] for _ in range(n + 1)]
    for _ in range(m):
        a = int(next(it)); b = int(next(it))
        adj[a].append(b)
    vis = [False] * (n + 1)
    stack = [1]
    vis[1] = True
    while stack:
        v = stack.pop()
        for u in adj[v]:
            if not vis[u]:
                vis[u] = True
                stack.append(u)
    return ' '.join(str(i) for i in range(1, n + 1) if vis[i])

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        out_lines.append(solve_one(it))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

